import{_ as t,a,b as n,c as l,d as o}from"./chunks/编辑配置.T0puvWjh.js";import{_ as r,o as d,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Telegram Channel شامل کریں","description":"","frontmatter":{},"headers":[],"relativePath":"ur/upload/telegram.md","filePath":"ur/upload/telegram.md","lastUpdated":1781962217000}'),c={name:"ur/upload/telegram.md"};function h(p,e,m,b,g,u){return d(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="telegram-channel-شامل-کریں" tabindex="-1">Telegram Channel شامل کریں <a class="header-anchor" href="#telegram-channel-شامل-کریں" aria-label="Permalink to &quot;Telegram Channel شامل کریں&quot;">​</a></h1><h2 id="شروع-کرنے-سے-پہلے-کیا-چاہیے" tabindex="-1">شروع کرنے سے پہلے کیا چاہیے <a class="header-anchor" href="#شروع-کرنے-سے-پہلے-کیا-چاہیے" aria-label="Permalink to &quot;شروع کرنے سے پہلے کیا چاہیے&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ضرورت</th><th>مقصد</th></tr></thead><tbody><tr><td>Telegram account</td><td>bot اور storage channel بنانے کے لیے</td></tr><tr><td><code>@BotFather</code></td><td>Telegram bot بنانے کے لیے</td></tr><tr><td>Telegram channel</td><td>files کا final storage destination</td></tr><tr><td><code>@userinfobot</code></td><td>channel کا <code>Chat ID</code> معلوم کرنے کے لیے</td></tr></tbody></table><h2 id="کہاں-شامل-کریں" tabindex="-1">کہاں شامل کریں <a class="header-anchor" href="#کہاں-شامل-کریں" aria-label="Permalink to &quot;کہاں شامل کریں&quot;">​</a></h2><ol><li>System Settings کھولیں۔</li><li>Upload Settings میں جائیں۔</li><li>اوپر دائیں طرف Add Channel پر کلک کریں۔</li><li><code>Telegram</code> منتخب کریں۔</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>کام</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>اس channel کا واضح نام، مثلاً &quot;Telegram Primary&quot;۔</td><td>Required</td></tr><tr><td>Active</td><td>اس channel کو enable یا disable کرتا ہے۔</td><td>Recommended</td></tr><tr><td>Bot Token</td><td>آپ کے Telegram bot کا token۔</td><td>Required</td></tr><tr><td>Session ID (Chat ID)</td><td>Telegram channel کی ID۔</td><td>Required</td></tr><tr><td>Relay Proxy URL (optional)</td><td>صرف اس وقت استعمال کریں جب Telegram access غیر مستحکم ہو۔ مکمل proxy URL لکھیں، <code>https://</code> سمیت۔</td><td>Optional</td></tr><tr><td>Remark</td><td>آئندہ maintenance کے لیے نوٹس۔</td><td>Optional</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="_1-telegram-bot-بنائیں" tabindex="-1">1. Telegram Bot بنائیں <a class="header-anchor" href="#_1-telegram-bot-بنائیں" aria-label="Permalink to &quot;1. Telegram Bot بنائیں&quot;">​</a></h3><ol><li>Telegram کھولیں اور <code>@BotFather</code> تلاش کریں۔</li><li>chat کھول کر <code>Start</code> پر کلک کریں۔</li><li><code>/newbot</code> بھیجیں۔</li><li>prompts کے مطابق bot display name درج کریں۔</li><li>prompts کے مطابق bot username درج کریں۔ username عموماً <code>bot</code> پر ختم ہونا چاہیے۔</li><li>bot بننے کے بعد <code>@BotFather</code> ایک bot token واپس دے گا۔</li></ol><p>یہی token ImgBed میں <code>Bot Token</code> کے طور پر درج کرنا ہے۔</p><p><img src="'+t+'" alt="Save the bot token" loading="lazy"></p><h3 id="_2-channel-بنائیں" tabindex="-1">2. Channel بنائیں <a class="header-anchor" href="#_2-channel-بنائیں" aria-label="Permalink to &quot;2. Channel بنائیں&quot;">​</a></h3><ol><li>Telegram میں New Channel پر کلک کریں۔</li><li>channel name درج کریں۔</li><li>channel creation مکمل کریں۔</li></ol><p>Public اور private دونوں channels استعمال کیے جا سکتے ہیں۔</p><p><img src="'+a+'" alt="Create a channel" loading="lazy"></p><h3 id="_3-bot-کو-channel-میں-شامل-کریں" tabindex="-1">3. Bot کو Channel میں شامل کریں <a class="header-anchor" href="#_3-bot-کو-channel-میں-شامل-کریں" aria-label="Permalink to &quot;3. Bot کو Channel میں شامل کریں&quot;">​</a></h3><ol><li>جو channel ابھی بنایا ہے اسے کھولیں۔</li><li>channel settings کھولیں۔</li><li>member یا administrator شامل کریں۔</li><li>اپنے بنائے ہوئے bot username کو تلاش کریں۔</li><li>bot کو channel میں شامل کریں۔</li></ol><p>زیادہ قابل اعتماد uploads کے لیے bot کو administrator permissions دیں۔</p><p><img src="'+n+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-user-info-get-id-idbot-سے-channel-id-حاصل-کریں" tabindex="-1">4. User Info - Get ID - IDbot سے Channel ID حاصل کریں <a class="header-anchor" href="#_4-user-info-get-id-idbot-سے-channel-id-حاصل-کریں" aria-label="Permalink to &quot;4. User Info - Get ID - IDbot سے Channel ID حاصل کریں&quot;">​</a></h3><ol><li>Telegram میں <code>@userinfobot</code> تلاش کریں۔ اس کا display name عموماً <code>User Info - Get ID - IDbot</code> ہوتا ہے۔</li><li>chat کھول کر <code>Start</code> پر کلک کریں۔</li><li>bot کے options میں سے <code>Channel</code> منتخب کریں۔</li><li>message picker میں target channel منتخب کریں اور اسے <code>@userinfobot</code> کو بھیجیں۔</li><li>جب <code>@userinfobot</code> نتیجہ دے، تو <code>Id: -100...</code> کے طور پر دکھایا گیا number copy کریں۔</li></ol><p><code>-100</code> سے شروع ہونے والا number وہی <code>Session ID (Chat ID)</code> ہے جو ImgBed کو چاہیے۔</p><p><img src="'+l+'" alt="Get the channel ID" loading="lazy"></p><h3 id="_5-imgbed-میں-telegram-channel-بھریں" tabindex="-1">5. ImgBed میں Telegram Channel بھریں <a class="header-anchor" href="#_5-imgbed-میں-telegram-channel-بھریں" aria-label="Permalink to &quot;5. ImgBed میں Telegram Channel بھریں&quot;">​</a></h3><p>channel configuration dialog پر واپس جائیں اور fields یوں بھریں:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>اپنی مرضی کا channel name، مثلاً <code>TelegramPrimary</code>۔</td></tr><tr><td>Active</td><td>Recommended۔</td></tr><tr><td>Bot Token</td><td><code>@BotFather</code> سے ملا ہوا bot token۔</td></tr><tr><td>Session ID (Chat ID)</td><td><code>@userinfobot</code> سے ملا ہوا <code>-100...</code> number۔</td></tr><tr><td>Relay Proxy URL (optional)</td><td>صرف ضرورت ہو تو، مثلاً <code>https://your-tg-proxy.example.com</code>۔</td></tr><tr><td>Remark</td><td>optional notes۔</td></tr></tbody></table><p>کام مکمل ہو جائے تو Save پر کلک کریں۔</p><p><img src="'+o+`" alt="Edit the configuration" loading="lazy"></p><h2 id="verify-کیسے-کریں" tabindex="-1">Verify کیسے کریں <a class="header-anchor" href="#verify-کیسے-کریں" aria-label="Permalink to &quot;Verify کیسے کریں&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Verify کرنے کا طریقہ</th></tr></thead><tbody><tr><td>Channel card appears</td><td>Save کے بعد Upload Settings میں Telegram channel card نظر آنا چاہیے۔</td></tr><tr><td>Channel can be enabled</td><td>Active switch on رہنا چاہیے۔</td></tr><tr><td>Configuration is saved</td><td>detail view میں Bot Token اور Chat ID محفوظ دکھنے چاہئیں۔</td></tr><tr><td>Upload works</td><td>ایک test image upload کریں اور دیکھیں کہ وہ target Telegram channel میں آتی ہے یا نہیں۔</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@BotFather سے bot بنائیں</span></span>
<span class="line"><span>-&gt; Bot Token محفوظ کریں</span></span>
<span class="line"><span>-&gt; Telegram channel بنائیں</span></span>
<span class="line"><span>-&gt; bot کو channel میں شامل کریں اور administrator permissions دیں</span></span>
<span class="line"><span>-&gt; @userinfobot تلاش کریں اور Channel منتخب کریں</span></span>
<span class="line"><span>-&gt; channel کا کوئی message @userinfobot کو forward کریں</span></span>
<span class="line"><span>-&gt; واپس آنے والا Id: -100... copy کریں</span></span>
<span class="line"><span>-&gt; ImgBed میں Bot Token اور Chat ID درج کریں</span></span>
<span class="line"><span>-&gt; Save کریں اور test image upload کریں</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const T=r(c,[["render",h]]);export{_ as __pageData,T as default};
